<template>
  <div class="container-fluid">
    <div class="row">
        <div class="col-12 col-md-12">
            <div class="row">
                <div class="col-12 m-3">
                    <h2>
                        <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="currentColor" class="bi bi-pencil-fill" viewBox="0 0 16 16">
                            <path d="M12.854.146a.5.5 0 0 0-.707 0L10.5 1.793 14.207 5.5l1.647-1.646a.5.5 0 0 0 0-.708l-3-3zm.646 6.061L9.793 2.5 3.293 9H3.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.5h.5a.5.5 0 0 1 .5.5v.207l6.5-6.5zm-7.468 7.468A.5.5 0 0 1 6 13.5V13h-.5a.5.5 0 0 1-.5-.5V12h-.5a.5.5 0 0 1-.5-.5V11h-.5a.5.5 0 0 1-.5-.5V10h-.5a.499.499 0 0 1-.175-.032l-.179.178a.5.5 0 0 0-.11.168l-2 5a.5.5 0 0 0 .65.65l5-2a.5.5 0 0 0 .168-.11l.178-.178z"/>
                        </svg>
                        編輯商品
                    </h2>
                </div>
            </div>
            <div>
                <div class="mb-3">
                    <label for="newProductName" class="form-label">商品名稱</label>
                    <input v-model="productName" type="text" class="form-control" id="newProductName" required>
                </div> 
                <div class="mb-3">
                    <label for="productDesc" class="form-label">商品描述</label>
                    <input v-model="productDesc" type="text" class="form-control" id="productDesc" placeholder="描述商品...">
                </div> 
                <div class="mb-3">
                    <label for="productPrice" class="form-label">商品價格</label>
                    <input  v-model.number="productPrice" type="text" class="form-control" id="productPrice" required >
                </div> 
                <div class="mb-3">
                    <label for="productStock" class="form-label">商品庫存</label>
                    <input  v-model.number="productStock" type="text" class="form-control" id="productStock" required>
                </div> 
                <div class="mb-3">
                    <label for="category" class="form-label">商品類別</label>
                    <input v-model="category" type="text" class="form-control" id="category" required>
                </div> 
                <div class="mb-3">
                    <label for="productImg" class="form-label">商品圖片</label>
                    <input v-model="productImg" type="text" class="form-control" id="productImg" placeholder="請輸入網址" required>
                </div> 
            </div>
            <div class="row">
                <div class="col-12 col-md-12">
                    <button id="submitBtn" @click="submitEditProduct" class="btn btn-success w-100 mb-3">
                        <template v-if="!submiting">
                            <div>
                                新增商品
                            </div>
                        </template>
                        <template v-if="submiting">
                            <div>
                                <div class="spinner-border" role="status">
                                    <span class="visually-hidden">Loading...</span>
                                </div>
                            </div>
                        </template>
                    </button>
                    <div v-if="isSubmitSuccess" class="alert alert-success text-center" role="alert">
                        商品新增成功
                    </div>
                    <div v-if="submitFailed" class="alert alert-danger" role="alert">
                        商品新增失敗！請正確填寫每一欄位
                    </div>
                </div>
            </div>
                
        </div>
    </div>
  </div>
</template>

<script>
import {toRefs,watch,ref,toRaw,onMounted} from 'vue'
import axios from 'axios'
import { useBackendInfoTempStore } from '@/store/backendInfoTemp'
import {useRouter} from 'vue-router'
export default {
  name:'BackEndEditProduct',
  setup(){
    let router =useRouter()
    let backendProductStore =useBackendInfoTempStore()
    let submiting=ref(false)
    let submitFailed=ref(false)
    let isSubmitSuccess=ref(false)
    let product = backendProductStore.product


    function submitEditProduct(){
        submiting.value=true
        this.submitFailed=false
        for(let detail in product){
           if(product[detail]===''){
            this.submitFailed=true
            submiting.value=false
               return
           }
        }
        
        
        
        axios.post('/addproductentity',toRaw(product),{headers:{'contentType':'application/jason'}}).then(
            () => {
                isSubmitSuccess.value=true
                submiting.value=false
                for(let detail in product){
                    product[detail]=''
                }
            }
        )        

    }
    
   watch(()=>product.productPrice,()=>{
    if(!/^[1-9]\d*$/.test(product.productPrice)){
        product.productPrice=''
    }
   },{deep:true})

   watch(()=>product.productStock,()=>{
    if(!/^[1-9]\d*$/.test(product.productStock)){
        product.productStock=''
    }
   },{deep:true})

   onMounted(()=>{
      for(let detail in product){
        if(product[detail]===''){
            router.push('/backenddashboard/products')
        }
      }
   })


    return{
        ...toRefs(product),
        isSubmitSuccess,
        submitEditProduct,
        submiting,
        submitFailed
    }
    }
    
}
</script>

